INSERT INTO `oauth_refresh_tokens` VALUES ('01db4ed1e57d77fff6ea5cab17a8f668f2f37782a10b380f8269c0db0c3b2308bb66d5e638c12cb5','5b0dbf2451a4216639fa53356cc994597e579359cf67e3e86eafd06164c732da9461cf4ade941634',0,'2023-07-21 04:31:42'),('0a12d94a38346c4910809f2420e7b7219698428afb85d9873b1874b24fb1cd69358d581fefbb8830','c821ef32829ecc7beda19b48c5362c294a91580ad1075c9a0d05815fc943f59b20defb3a210abba2',0,'2023-07-21 01:32:24'),('11fbdcf11daafccf34651362b794ada7a9c41d37cbc0b4f7b88adc022b44caaeade34b5025e640f4','0ccafc7d45652b579940674c9281f450f630f7cbf5b0d667f10d110c5c6d6f33818f2a4b90efcc6a',0,'2023-07-19 18:04:26'),('14b14f8beea52ffdf8eaad813e7b98c78c155480e21d623092387c49dbfe335d5506aff3461fe86b','fe6866b493d6c36ac612ca4d5313e6c512a2fe9d61bd6322cdb2c7c17414c8a2b9867b88c5368cf4',0,'2023-07-19 20:35:49'),('28cebfdca4548b82ae28809423804f560415a1635730060ab2151d09d61c15eaa0be4f6d773b470d','a731274697de70cd4d206787b9feb53380606e3af0d30f288c3f65f6ee147c1e1f905922209aa39f',0,'2023-07-19 21:40:21'),('338a031e42f01ced841d89761d542d62c0ef763bab76d094c3023aa9915275bceca71308c77c3eaa','165f5703901ff8c8c657dd2cdd0eab1c016c9eea67272d144920a58e075b0a47a8b7b29e5a3b29b6',0,'2023-07-19 18:09:18'),('3b0d838f89b6a63f7206d38f4dd2508a9de894a58e50976af967fc0149b90e92c2e8e49ab938f2a1','75a4a94b07adb6577ebb47b570fb34d0f049913c2301d573522c32fde08c2b915de652f9442e97ec',0,'2023-07-21 03:09:53'),('3f6e5e3ec57036a304649d5de1504ba0bb3b4257f87af2bc86c902cb29feee6b34627335b045c5ee','a919dce6c3bf72010550940b3ca7110cd93060bbf626d881923eb59acb59cdb406cd0a50ea15481d',0,'2023-07-20 00:47:53'),('440644d10ed384737e996c711059067864056ebc4d514ce250dd4459e2b0f79beafb5e650e0083fc','9e0310e87d389737b8470715c35195ccb9cbf891a0f6a478f5ed2dc8fa209be7c1e345b2eb509dad',0,'2023-07-21 16:16:28'),('4e123de40e595ff05dafd331816c6fc6740da25a1b874a6bb29732a18da808e0c7449339ac551b4b','6442c3092a181d9c3718d6df02df54cac037cf67de66b648fe64bf188d235f19a778a5396af93b2d',0,'2023-07-20 22:53:25'),('4f2da5c7ddec4af6f1fe646dd506c0d0ab15